# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, exceptions as es_exceptions
import os
import time
import logging

app = Flask(__name__)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

ES_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ES_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")

es = Elasticsearch(
    ES_URL,
    request_timeout=2,
    max_retries=2,
    retry_on_timeout=True,
    http_compress=True,
)

@app.route("/api/search", methods=["GET"])
def search_products():
    q = request.args.get("q", "").strip()
    if not q:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    size = min(int(request.args.get("size", 20)), 100)
    from_ = max(int(request.args.get("from", 0)), 0)

    body = {
        "from": from_,
        "size": size,
        "_source": ["id", "name", "price", "image_url", "category", "brand", "in_stock"],
        "query": {
            "multi_match": {
                "query": q,
                "fields": [
                    "name^5",
                    "brand^3",
                    "category^2",
                    "description",
                    "tags"
                ],
                "type": "best_fields",
                "operator": "and",
                "fuzziness": "AUTO"
            }
        },
        "sort": [
            "_score",
            {"popularity": "desc"},
            {"updated_at": "desc"}
        ]
    }

    start = time.time()
    try:
        resp = es.search(index=ES_INDEX, body=body)
        hits = resp.get("hits", {}).get("hits", [])
        results = []
        for hit in hits:
            source = hit.get("_source", {})
            source["score"] = hit.get("_score")
            results.append(source)

        elapsed_ms = round((time.time() - start) * 1000, 2)
        return jsonify({
            "query": q,
            "took_ms": elapsed_ms,
            "total": resp.get("hits", {}).get("total", {}).get("value", 0) if isinstance(resp.get("hits", {}).get("total", {}), dict) else resp.get("hits", {}).get("total", 0),
            "results": results
        }), 200

    except es_exceptions.ConnectionError:
        logger.exception("Elasticsearch connection error")
        return jsonify({"error": "Search service unavailable"}), 503
    except es_exceptions.TransportError as e:
        logger.exception("Elasticsearch transport error: %s", e)
        return jsonify({"error": "Search failed"}), 502
    except Exception:
        logger.exception("Unexpected error during search")
        return jsonify({"error": "Internal server error"}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", 5000)))